using System.Net.Http.Headers; using System.Text.Json; using LifeOS.Core.IntegrationConnectors.Gmail;
namespace LifeOS.Shared.IntegrationConnectors.Gmail;
public sealed class GmailApiProvider(HttpClient http,Func<Task<string>> tokenFactory):IReadOnlyGmailProvider
